from __future__ import annotations
import json
from dataclasses import dataclass, field
from typing import Any

@dataclass
class ContractViolation:
    chunk_id: str
    field: str
    rule: str
    actual_value: Any

@dataclass
class ContractValidationResult:
    total_chunks: int
    violations: list[ContractViolation] = field(default_factory=list)
    sla_pass: dict[str, bool] = field(default_factory=dict)

    def passes(self) -> bool:
        return len(self.violations) == 0 and all(self.sla_pass.values())

REQUIRED_FIELDS = {
    "doc_id", "chunk_id", "content", "classification_label",
    "permitted_apps", "source_updated_at", "content_class",
}
ALLOWED_CLASSIFICATION = {"public", "internal", "confidential", "restricted"}
ALLOWED_CONTENT_CLASS = {"regulatory", "policy", "product_doc", "research", "market_data"}
CONTENT_MIN = 50
CONTENT_MAX = 2000

def validate_batch_against_contract(
    chunks: list[dict[str, Any]],
    embedding_model: str,
    expected_embedding_model: str = "text-embedding-3-small",
) -> ContractValidationResult:
    violations: list[ContractViolation] = []

    for chunk in chunks:
        cid = chunk.get("chunk_id", "<unknown>")

        # Required fields
        for f in REQUIRED_FIELDS:
            if not chunk.get(f):
                violations.append(ContractViolation(cid, f, "required_field_missing", chunk.get(f)))

        # Content length
        content = chunk.get("content", "")
        if not (CONTENT_MIN <= len(content) <= CONTENT_MAX):
            violations.append(ContractViolation(cid, "content", "length_out_of_range", len(content)))

        # Enum validity
        cls_label = chunk.get("classification_label")
        if cls_label and cls_label not in ALLOWED_CLASSIFICATION:
            violations.append(ContractViolation(cid, "classification_label", "invalid_enum", cls_label))

        cc = chunk.get("content_class")
        if cc and cc not in ALLOWED_CONTENT_CLASS:
            violations.append(ContractViolation(cid, "content_class", "invalid_enum", cc))

    # Batch-level SLA checks
    n = len(chunks)
    null_rate = sum(
        1 for c in chunks for f in REQUIRED_FIELDS if not c.get(f)
    ) / (n * len(REQUIRED_FIELDS)) if n else 0.0

    chunk_ids = [c.get("chunk_id") for c in chunks]
    dup_rate = (len(chunk_ids) - len(set(filter(None, chunk_ids)))) / n if n else 0.0

    sla_pass = {
        "null_rate": null_rate <= 0.01,
        "duplicate_rate": dup_rate == 0.0,
        "embedding_model": embedding_model == expected_embedding_model,
    }

    return ContractValidationResult(
        total_chunks=n,
        violations=violations,
        sla_pass=sla_pass,
    )
